import { WarehouseService } from "./warehouse-service";
import { Warehouse, WarehouseRepository } from "./warehouse-repository";
import { AppError } from "../shared/app-error";

function makeRepo(overrides?: Partial<WarehouseRepository>): WarehouseRepository {
  return {
    findById: jest.fn().mockResolvedValue(null),
    save: jest.fn().mockResolvedValue(undefined),
    ...overrides,
  };
}

describe("WarehouseService", () => {
  // AC1: Given a warehouse ID that exists, when getWarehouse is called, then the warehouse is returned
  it("AC1: returns the warehouse when the ID exists", async () => {
    const existing: Warehouse = { id: "wh-1", name: "Main Depot", capacity: 1000 };
    const repo = makeRepo({ findById: jest.fn().mockResolvedValue(existing) });
    const service = new WarehouseService(repo);

    const result = await service.getWarehouse("wh-1");

    expect(result).toEqual(existing);
    expect(repo.findById).toHaveBeenCalledWith("wh-1");
  });

  // AC2: Given a warehouse ID that does not exist, when getWarehouse is called, then throw WAREHOUSE_NOT_FOUND
  it("AC2: throws WAREHOUSE_NOT_FOUND when the ID does not exist", async () => {
    const repo = makeRepo({ findById: jest.fn().mockResolvedValue(null) });
    const service = new WarehouseService(repo);

    await expect(service.getWarehouse("wh-missing")).rejects.toMatchObject({
      code: "WAREHOUSE_NOT_FOUND",
    });
  });

  it("AC2: error is an AppError instance", async () => {
    const repo = makeRepo();
    const service = new WarehouseService(repo);

    const err = await service.getWarehouse("wh-missing").catch((e) => e);

    expect(err).toBeInstanceOf(AppError);
    expect(err.message).toContain("wh-missing");
  });

  // AC3: Given a warehouse and a new capacity, when updateCapacity is called,
  //      then the warehouse's capacity is updated and saved
  it("AC3: updates the warehouse capacity and persists it", async () => {
    const warehouse: Warehouse = { id: "wh-1", name: "Main Depot", capacity: 500 };
    const repo = makeRepo({ findById: jest.fn().mockResolvedValue(warehouse) });
    const service = new WarehouseService(repo);

    await service.updateCapacity("wh-1", 2000);

    expect(repo.save).toHaveBeenCalledWith({ ...warehouse, capacity: 2000 });
  });

  it("AC3: updateCapacity throws WAREHOUSE_NOT_FOUND when warehouse does not exist", async () => {
    const repo = makeRepo();
    const service = new WarehouseService(repo);

    await expect(service.updateCapacity("wh-ghost", 999)).rejects.toMatchObject({
      code: "WAREHOUSE_NOT_FOUND",
    });
    expect(repo.save).not.toHaveBeenCalled();
  });
});

